{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyPmoR7D83jB6igK301h6sCL"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","source":["import pandas as pd\n","import glob\n","import os\n","\n","def process_data():\n","    # Loading the JSON File\n","    json_files = glob.glob(\"/content/trends_20260409.json\")\n","\n","    if not json_files:\n","        print(\"Error: JSON files are not found in data folder.\")\n","        print(\"Please check JSON file.\")\n","        return\n","\n","    latest_file = max(json_files, key=os.path.getctime)\n","\n","    print(f\"Loading data from: {latest_file}\")\n","    df = pd.read_json(latest_file)\n","    print(f\"Loaded {len(df)} stories.\")\n","\n","    # Clean the Data\n","\n","    df = df.drop_duplicates(subset=['post_id'])\n","    print(f\"After removing duplicates: {len(df)}\")\n","\n","    df = df.dropna(subset=['post_id', 'title', 'score'])\n","    print(f\"After removing nulls: {len(df)}\")\n","\n","    df['score'] = df['score'].astype(int)\n","    df['num_comments'] = df['num_comments'].astype(int)\n","\n","    df = df[df['score'] >= 5]\n","    print(f\"After removing low scores (< 5): {len(df)}\")\n","\n","    df['title'] = df['title'].str.strip()\n","\n","    # Save as CSV and Summary\n","    output_path = \"data/trends_clean.csv\"\n","\n","    # Create the 'data' directory if it doesn't exist\n","    os.makedirs('data', exist_ok=True)\n","\n","    df.to_csv(output_path, index=False)\n","\n","    print(\"-\" * 30)\n","    print(f\"Saved {len(df)} rows to {output_path}\")\n","\n","    # Print the required summary of stories per category\n","    print(\"\\nStories per category:\")\n","    summary = df['category'].value_counts()\n","    print(summary)\n","\n","if __name__ == \"__main__\":\n","    process_data()"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"A0iYcvDQ_4im","executionInfo":{"status":"ok","timestamp":1775743219555,"user_tz":-330,"elapsed":54,"user":{"displayName":"Kaustubh Dawbhat","userId":"04829877058264364037"}},"outputId":"84df7788-c6a3-4075-f973-f10131f25b10"},"execution_count":11,"outputs":[{"output_type":"stream","name":"stdout","text":["Loading data from: /content/trends_20260409.json\n","Loaded 104 stories.\n","After removing duplicates: 90\n","After removing nulls: 90\n","After removing low scores (< 5): 89\n","------------------------------\n","Saved 89 rows to data/trends_clean.csv\n","\n","Stories per category:\n","category\n","technology       24\n","worldnews        22\n","sports           17\n","entertainment    16\n","science          10\n","Name: count, dtype: int64\n"]}]},{"cell_type":"code","source":[],"metadata":{"id":"IVzTvPT3_5m-"},"execution_count":null,"outputs":[]}]}